      interview: [
        { level: "Junior", q: "What is Infrastructure as Code?", a: "The managing and provisioning of infrastructure through code instead of manual processes.", type: "Conceptual" },
        { level: "Junior", q: "What is AWS CloudFormation?", a: "An AWS service that helps you model and set up your AWS resources so that you can spend less time managing them.", type: "Conceptual" },
        { level: "Junior", q: "CloudFormation vs Manual Console?", a: "CloudFormation is faster, repeatable, searchable (in version control), and less prone to human error.", type: "Conceptual" },
        { level: "Junior", q: "What is a 'stack' in CloudFormation?", a: "A collection of AWS resources that you can manage as a single unit.", type: "Conceptual" },
        { level: "Junior", q: "What are the common IaC tools in AWS?", a: "CloudFormation, CDK, Terraform, and SAM.", type: "Conceptual" },
        { level: "Junior", q: "What is a YAML file?", a: "A human-readable data serialization language used for CloudFormation templates.", type: "Conceptual" },
        { level: "Junior", q: "What is a 'Parameter' in CloudFormation?", a: "A way to pass custom values to your template at runtime (like choosing an instance type).", type: "Conceptual" },
        { level: "Junior", q: "What is a 'Resource' in CloudFormation?", a: "The actual AWS component being created (like an S3 bucket or EC2 instance).", type: "Conceptual" },
        { level: "Junior", q: "How do you delete all resources created by a template?", a: "By deleting the Stack; CloudFormation will clean up all associated resources.", type: "Coding" },
        { level: "Junior", q: "What is Terraform Plan?", a: "A command that shows what actions Terraform will take to reach the desired state defined in your code.", type: "Coding" },
        { level: "Junior", q: "What is HCL?", a: "HashiCorp Configuration Language, used to write Terraform files.", type: "Conceptual" },
        { level: "Junior", q: "What is an 'Output' in CloudFormation?", a: "A value returned after stack creation, useful for showing IPs or resource IDs in the console.", type: "Conceptual" },
        { level: "Junior", q: "Why use Version Control (Git) for IaC?", a: "To track changes, collaborate across teams, and allow for rollbacks to previous versions.", type: "Conceptual" },
        { level: "Junior", q: "What is 'Drift'?", a: "When the actual cloud environment differs from the configuration defined in your code (usually due to manual edits).", type: "Conceptual" },
        { level: "Mid", q: "What is the AWS CDK?", a: "The Cloud Development Kit. It allows you to define infrastructure using high-level programming languages like Python or TypeScript.", type: "Conceptual" },
        { level: "Mid", q: "Terraform vs CloudFormation?", a: "CloudFormation is AWS native. Terraform is cloud-agnostic (works on AWS, Azure, GCP, etc.) and uses HCL syntax.", type: "Conceptual" },
        { level: "Mid", q: "What is a 'State file' in Terraform?", a: "A file that maps your code to the real-world resources in the cloud, helping Terraform understand what to create, update, or delete.", type: "Conceptual" },
        { level: "Mid", q: "Explain 'Change Sets' in CloudFormation.", a: "A way to preview how proposed changes to a stack might impact your running resources before you execute them.", type: "Conceptual" },
        { level: "Mid", q: "What are 'Intrinsic Functions'?", a: "Built-in functions like !Ref (referencing a resource) or !GetAtt (getting an attribute like Arn).", type: "Conceptual" },
        { level: "Mid", q: "Explain 'Mappings' in CloudFormation.", a: "A way to store lookup tables (like which AMI to use in which region) within the template.", type: "Conceptual" },
        { level: "Mid", q: "What is 'CDK Synthesis'?", a: "The process of executing your CDK app and producing a CloudFormation template.", type: "Conceptual" },
        { level: "Mid", q: "How do you share values across CloudFormation Stacks?", a: "By using 'Export' in one stack and '!ImportValue' in another.", type: "Coding" },
        { level: "Mid", q: "What is 'State Locking' and why is it important?", a: "Mechanisms (like DynamoDB with S3) that prevent two people from updating infrastructure simultaneously and corrupting the state.", type: "Scenario" },
        { level: "Mid", q: "What is 'DeletionPolicy'?", a: "A property that tells AWS what to do with a resource when a stack is deleted (e.g. Delete, Retain, or Snapshot).", type: "Conceptual" },
        { level: "Mid", q: "Explain Terraform 'Modules'.", a: "Reusable, self-contained packages of Terraform configurations that manage a specific group of resources.", type: "Conceptual" },
        { level: "Mid", q: "How do you handle 'Drift' in CloudFormation?", a: "By running 'Drift Detection' and then updating the template or manually fixing the resource to match the code.", type: "Scenario" },
        { level: "Senior", q: "How would you handle sensitive data (passwords) in IaC?", a: "By using Parameters and referencing AWS Secrets Manager or Systems Manager Parameter Store instead of hardcoding values.", type: "Scenario" },
        { level: "Senior", q: "Explain the 'Immutable Infrastructure' pattern.", a: "Instead of updating existing servers, you always deploy new ones from code and destroy the old ones, leading to more predictable environments.", type: "Conceptual" },
        { level: "Senior", q: "How does Terraform handle dependency management?", a: "Terraform automatically builds a dependency graph between resources to ensure they are created in the correct order.", type: "Conceptual" },
        { level: "Senior", q: "What are the common pitfalls of IaC?", a: "Deleting a state file by accident, manual changes causing 'drift', and complex dependency cycles in large stacks.", type: "Scenario" },
        { level: "Senior", q: "How do you test your IaC code?", a: "Using linters (like tflint), security scanners (like Checkov), and running 'Plan' or 'Dry-run' before any deployment.", type: "Scenario" },
        { level: "Senior", q: "Explain 'CloudFormation StackSets'.", a: "Allows you to create, update, or delete stacks across multiple accounts and regions with a single operation.", type: "Conceptual" },
        { level: "Senior", q: "How would you implement 'CI/CD' for Infrastructure?", a: "Using tools like GitHub Actions or CodePipeline to run 'lint', 'plan', and 'apply' automatically when code is pushed.", type: "Scenario" },
        { level: "Senior", q: "What is 'Policy-as-Code'?", a: "Using tools like OPA (Open Policy Agent) or CloudFormation Guard to enforce security rules (e.g. 'no public S3 buckets') during the IaC build phase.", type: "Conceptual" },
        { level: "Senior", q: "Explain 'Custom Resources' in CloudFormation.", a: "Running a Lambda function during stack creation/update to perform tasks not natively supported by CloudFormation (like looking up an AMI ID or calling a 3rd party API).", type: "Scenario" },
        { level: "Senior", q: "How do you handle 'State Migration' in Terraform?", a: "Using 'terraform state mv' commands to re-organize resources without destroying and recreating them.", type: "Scenario" },
        { level: "Senior", q: "Explain 'Aurora Serverless v2' scaling architecture.", a: "Scales in increments as small as 0.5 ACUs (Aurora Capacity Units) based on actual CPU and memory utilization, reacting in milliseconds.", type: "Conceptual" },
        { level: "Junior", q: "What is 'RDS'?", a: "Relational Database Service; makes it easy to set up, operate, and scale a relational database (MySQL, Postgres, etc.) in the cloud.", type: "Conceptual" },
        { level: "Junior", q: "What is 'Aurora'?", a: "A MySQL and PostgreSQL-compatible relational database built for the cloud by AWS.", type: "Conceptual" },
        { level: "Mid", q: "What is 'Multi-AZ' deployment in RDS?", a: "Automatically provisioning a synchronous standby instance in a different AZ for high availability.", type: "Conceptual" },
        { level: "Mid", q: "What is a 'Read Replica'?", a: "An asynchronous copy of the database used to offload read traffic from the primary instance.", type: "Conceptual" },
        { level: "Senior", q: "How do you handle 'Database Passwords' securely in RDS?", a: "Using 'IAM Database Authentication' to connect without a password, or storing secrets in AWS Secrets Manager with auto-rotation.", type: "Scenario" },
        { level: "Senior", q: "Explain 'RDS Proxy'.", a: "A fully managed, highly available database proxy that pools and shares connections to improve application scalability and failover times.", type: "Conceptual" },
        { level: "Senior", q: "How do you perform 'Zero-Downtime Patching' in Aurora?", a: "Aurora uses 'Zero-Downtime Patching' (ZDP) to attempt to preserve client connections while the database engine restarts.", type: "Scenario" },
        { level: "Senior", q: "Explain 'Aurora Global Database'.", a: "Spans multiple AWS regions, providing low-latency global reads and fast disaster recovery with a sub-second lag.", type: "Conceptual" },
        { level: "Junior", q: "Which DB engines does RDS support?", a: "MySQL, PostgreSQL, MariaDB, Oracle, SQL Server, and Amazon Aurora.", type: "Conceptual" },
        { level: "Mid", q: "What is 'Snapshot' in RDS?", a: "A manual or automatic backup of the entire database instance stored in S3.", type: "Conceptual" },
        { level: "Senior", q: "Explain 'SAM' vs 'CDK'.", a: "SAM is a specialized extension of CloudFormation for serverless; CDK is a higher-level general-purpose framework using real languages.", type: "Conceptual" },
        { level: "Senior", q: "How do you manage 'Multi-Environment' architectures in IaC?", a: "Using Terraform Workspaces, separate folders, or separate state files per environment (dev/staging/prod).", type: "Scenario" },
        { level: "Senior", q: "What is 'Construct' library in CDK?", a: "A collection of pre-baked, well-architected patterns (Level 2/3 constructs) that follow AWS best practices.", type: "Conceptual" },
        { level: "Senior", q: "How do you troubleshoot 'Circular Dependencies' in CloudFormation?", a: "By using intermediate resources (like a Security Group rule resource instead of an inline rule) to break the cycle.", type: "Scenario" },
        { level: "Senior", q: "Explain 'Terraform Cloud' benefits at an enterprise level.", a: "Provides a centralized UI, role-based access control, remote state management, and policy enforcement via Sentinel.", type: "Conceptual" },
        { level: "Senior", q: "How would you use IaC to recover from a regional outage (DR)?", a: "By having your IaC code ready to deploy to a 'DR' region, ensuring all networking, databases, and app servers are recreated identical to the primary.", type: "Scenario" }
      ]
